query:
SELECT id, batchNo, poNumber, vendorName, importedCategoryName, importedBrandName, categoryId, stationCode, productStatus, sheetRowNumber FROM products WHERE batchNo = '00500025282';
SELECT se.id, se.stationCode, se.eventType, se.businessDate, se.categoryId, se.subtypeCode, se.countForProductivity, psd.id AS detailId, psd.targetConfigId, psd.earnedPoints FROM station_events se INNER JOIN products p ON p.id = se.productId LEFT JOIN productivity_score_details psd ON psd.stationEventId = se.id WHERE p.batchNo = '00500025282' ORDER BY se.id ASC;
SELECT COUNT(*) AS purchaseSheetRows FROM products WHERE batchNo = '00500025282' AND sheetRowNumber IS NOT NULL;

